; Rewrite the tilemap with tile indices low enough to exist in 8bpp
; (32 words/tile against a 512-word font = tiles $00-$0F).
.proc scene_low_tiles
    .a16
    .i16
    sep #$20
    .a8
    lda #$80
    sta VMAIN
    rep #$30
    .a16
    .i16
    ldx #MAP_BASE
    stx VMADDL
    ldx #$0000
@cell:
    txa
    and #$000F        ; tile $00-$0F
    sta f:V_TMP
    txa
    lsr a
    lsr a
    lsr a
    lsr a
    and #$0007
    .repeat 10
    asl a
    .endrepeat
    ora f:V_TMP       ; palette in bits 10-12
    sta VMDATAL
    inx
    cpx #(SCREEN_COLS * 32)
    bne @cell
    rts
.endproc

