    txa
    and #$003F
    clc
    adc #$0041        ; a letter glyph, so a flip is obvious
    sta f:V_TMP
    txa
    and #$0001
    beq :+
    lda #$4000        ; H flip
    bra :++
    :
    lda #$0000
    :
    sta f:V_TMP2
    txa
    and #$0020        ; every other row of cells
    beq :+
    lda #$8000        ; V flip
    bra :++
    :
    lda #$0000
    :
    ora f:V_TMP2
    ora f:V_TMP
    sta $2118
    inx
    cpx #(SCREEN_COLS * 32)
    bne @flipcell
